import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    # {This new algorithm incorporates the variance in travel times combined with customer request density and urgency to prioritize nodes and manage dynamic wait times.}
    if not unvisited_customers:
        return None

    max_priority = -float('inf')
    best_node = None

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = np.linalg.norm(cur_truck_pos - customer_pos) / truck_speed
        arrival_time = current_time + travel_time
        start, end = time_windows[idx]

        if arrival_time < start:
            wait_time = start - arrival_time
            arrival_time = start
        else:
            wait_time = 0

        if arrival_time <= end:
            urgency = 1 / (end - current_time + 1)
            travel_variance_factor = np.var([np.linalg.norm(pos - customer_pos) / truck_speed for pos in all_truck_pos])

            priority_score = urgency + (1 / (travel_time + 1)) - wait_time + travel_variance_factor

            if priority_score > max_priority:
                max_priority = priority_score
                best_node = idx

    return best_node

