def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    # {My new algorithm utilizes a priority scoring system based on inverse travel time relevance, time window tightness, and unique allocations to optimize route selection and allow for strategic waiting when necessary.}
    if not unvisited_customers:
        return None

    max_priority = -float('inf')
    best_node = None

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = np.linalg.norm(cur_truck_pos - customer_pos) / truck_speed
        arrival_time = current_time + travel_time
        start, end = time_windows[idx]

        if arrival_time < start:
            wait_time = start - arrival_time
            arrival_time = start
        else:
            wait_time = 0

        if arrival_time <= end:
            time_window_tightness = 1 / (end - start + 1)

            priority_score = (1 / (travel_time + 1)) + time_window_tightness - wait_time

            unique_allocation = len(set(map(tuple, unvisited_customers))) / len(unvisited_customers)
            priority_score *= unique_allocation

            if priority_score > max_priority:
                max_priority = priority_score
                best_node = idx

    return best_node
